const j = $input.item.json;
let mensaje = '', remitente = '';
try {
  const m = (j.messages && j.messages[0]) || (j.entry && j.entry[0].changes[0].value.messages[0]);
  mensaje = m.text ? m.text.body : (m.body || '');
  remitente = m.from || '';
} catch (e) { mensaje = j.message || ''; }
return { json: { origen: 'whatsapp', canal: 'WhatsApp', producto: '', agencia: '', mensaje, cliente: { telefono: remitente }, remitente } };

const b = $input.item.json.body || $input.item.json;
let canal = b.object === 'instagram' ? 'Instagram' : 'Facebook';
let mensaje = '', remitente = '';
try {
  const ev = b.entry[0].messaging[0];
  mensaje = ev.message ? (ev.message.text || '') : '';
  remitente = ev.sender ? ev.sender.id : '';
} catch (e) { mensaje = b.mensaje || ''; canal = b.canal || canal; }
return { json: { origen: 'meta', canal, producto: '', agencia: '', mensaje, cliente: { id: remitente }, remitente } };

const b = $input.item.json.body || $input.item.json;
const cli = b.cliente || {};
return { json: { origen: 'demo', canal: b.canal || 'Demo', producto: b.producto || '', agencia: b.agencia || '', mensaje: b.mensaje || '', cliente: cli, remitente: b.remitente || cli.telefono || cli.id || '' } };

// === 2. TOKENIZACION (on-premise) ===
const j = $input.item.json;
const cliente = j.cliente || {};
let texto = (j.mensaje || '').toString();
const mapa = {};
function tk(v, p) { if (!v) return; const t = '{' + p + '_001}'; mapa[t] = v; if (texto.includes(v)) texto = texto.split(v).join(t); }
tk(cliente.nombre, 'NAME');
tk(cliente.ci, 'CI');
tk(cliente.cuenta, 'ACCT');
tk(cliente.telefono, 'PHONE');
return { json: { ...j, texto_tokenizado: texto, mapa_tokens: mapa, cliente_visible: { nombre: cliente.nombre || null, ci: cliente.ci || null } } };

// === 3. INTERPRETAR: usa Claude si respondio JSON valido; si no, REGLAS ===
const base = $('Tokenizar (PII)').item.json;
const resp = $input.item.json;
let tipo, producto, categoria, severidad, fuente = 'reglas';

try {
  let txt = '';
  if (resp && resp.choices && resp.choices[0] && resp.choices[0].message) txt = resp.choices[0].message.content || '';
  else if (resp && resp.content && resp.content[0] && resp.content[0].text) txt = resp.content[0].text;
  else if (typeof resp === 'string') txt = resp;
  if (txt) {
    const a = txt.indexOf('{'); const b = txt.lastIndexOf('}');
    if (a >= 0 && b > a) { const c = JSON.parse(txt.slice(a, b + 1)); if (c.tipo) { tipo = c.tipo; producto = c.producto; categoria = c.categoria; severidad = c.severidad; fuente = 'ia (groq)'; } }
  }
} catch (e) {}

if (!tipo) {
  const t = (base.texto_tokenizado || '').toLowerCase();
  producto = base.producto || 'desconocido';
  if (t.includes('altoke') || t.includes('qr')) producto = 'altoke';
  else if (t.includes('appsol')) producto = 'appSol';
  else if (t.includes('solnet')) producto = 'Solnet';
  tipo = 'queja'; severidad = 'baja'; categoria = 'general';
  const conocidas = [['cambie de celular','cambié de celular','cambie de dispositivo','nuevo celular','nuevo dispositivo'], ['escanear','carnet','extranjero'], ['sigue saliendo la deuda','sigue la deuda','no me han devuelto','ya pague','pague y sigue']];
  const cats = ['acceso','acceso','transacciones'];
  let conocida = false;
  for (let i = 0; i < conocidas.length; i++) { if (conocidas[i].some(x => t.includes(x))) { conocida = true; categoria = cats[i]; break; } }
  if (!conocida) {
    const senales = ['no puedo entrar','no puedo iniciar','no inicia','no carga','no funciona','caido','caida','no puedo transferir','qr no','no procesa','error general','se cae','app caida','no puedo acceder','no anda','nadie puede'];
    const criticas = ['login','iniciar sesion','transferencia','transferir','qr','ach'];
    if (senales.some(k => t.includes(k))) { tipo = 'incidente'; severidad = 'alta'; }
    if (criticas.some(k => t.includes(k)) && (t.includes('no ') || t.includes('error') || t.includes('falla'))) { tipo = 'incidente'; severidad = 'alta'; }
    if (t.includes('transfer') || t.includes('pago') || t.includes('qr')) categoria = 'transacciones';
    else if (t.includes('iniciar') || t.includes('login') || t.includes('entrar') || t.includes('sesion') || t.includes('acceso')) categoria = 'acceso';
    else if (t.includes('lento') || t.includes('demora') || t.includes('timeout')) categoria = 'rendimiento';
    else if (t.includes('saldo') || t.includes('movimiento') || t.includes('comprobante')) categoria = 'datos';
  }
}
if (tipo !== 'queja' && tipo !== 'incidente') tipo = 'queja';
return { json: { ...base, tipo, severidad: severidad || 'baja', producto: producto || 'desconocido', categoria: categoria || 'general', clasificado_por: fuente } };

// === 4. AGRUPAR INCIDENTES + CONTAR AFECTADOS ===
const j = $input.item.json;
const sd = $getWorkflowStaticData('global');
sd.incidentes = sd.incidentes || {};
if (j.tipo === 'incidente') {
  const clave = (j.producto || 'x') + '|' + (j.categoria || 'general');
  if (!sd.incidentes[clave]) { sd.incidentes[clave] = { caso_id: 'INC-' + Date.now().toString().slice(-5), afectados: 0 }; }
  sd.incidentes[clave].afectados += 1;
  j.caso_id = sd.incidentes[clave].caso_id;
  j.afectados = sd.incidentes[clave].afectados;
  j.incidente_nuevo = sd.incidentes[clave].afectados === 1;
} else {
  j.caso_id = 'QJA-' + Date.now().toString().slice(-5);
  j.afectados = 1;
}
return { json: j };

// === 6a. PAQUETE DE INCIDENTE + asignar EQUIPO ===
const j = $input.item.json;
let equipo = 'Mesa de Incidentes TI';
if (j.categoria === 'transacciones' || j.producto === 'altoke') equipo = 'Equipo Pagos/QR';
else if (j.categoria === 'acceso') equipo = 'Equipo Seguridad/Accesos';
else if (j.categoria === 'rendimiento') equipo = 'Infraestructura/TI';
else if (j.producto === 'appSol' || j.producto === 'Solnet') equipo = 'DevOps Aplicaciones';
return { json: { ...j, resultado: 'INCIDENTE', estado: 'En análisis', equipo_asignado: equipo, paquete_para_desarrollo: { que_falla: (j.categoria || 'general') + ' en ' + (j.producto || 'desconocido'), producto: j.producto, severidad: j.severidad, afectados: j.afectados, incidente_nuevo: j.incidente_nuevo, datos_para_reproducir: { canal: j.canal, producto: j.producto, agencia: j.agencia, texto_tokenizado: j.texto_tokenizado }, equipo_asignado: equipo, estado: 'En análisis' }, respuesta_cliente: 'Recibimos tu reporte. Lo vinculamos al incidente ' + j.caso_id + ' (afectados: ' + j.afectados + '). Lo derivamos a ' + equipo + '. Te avisaremos por este mismo canal. Estado: En análisis.' } };

// === 6b. RESPUESTA QUEJA (Playbook Vivo) - se resuelve sola ===
const j = $input.item.json;
const playbook = {
  acceso: { pasos: ['1. Cierra y vuelve a abrir la app', '2. Si cambiaste de dispositivo, reactiva tus tokens', '3. Si persiste, vuelve a escanear tu carnet'], respuesta: 'Para resolver tu acceso: reactiva tus tokens o vuelve a escanear tu carnet siguiendo los pasos. Si continúa, escríbenos.' },
  transacciones: { pasos: ['1. Verifica tu comprobante', '2. Espera el transcurso del día (conciliación)', '3. Si no se refleja, te contactamos'], respuesta: 'Tu operación está en proceso. Por favor espera el transcurso del día; se reflejará tras la conciliación.' },
  rendimiento: { pasos: ['1. Revisa tu conexión', '2. Cierra otras apps', '3. Actualiza la app'], respuesta: 'Puede ser conexión o versión. Sigue los pasos; si continúa, avísanos.' },
  datos: { pasos: ['1. Refresca la pantalla', '2. Espera unos minutos', '3. Si no aparece, te ayudamos'], respuesta: 'Tu información puede tardar en actualizarse. Refresca; si no aparece, escríbenos.' },
  general: { pasos: ['1. Revisa tu conexión', '2. Actualiza la app'], respuesta: 'Gracias por tu consulta. Sigue los pasos; si continúa, escríbenos.' }
};
const pb = playbook[j.categoria] || playbook.general;
return { json: { ...j, resultado: 'QUEJA', estado: 'Resuelto (autoservicio)', equipo_asignado: 'Ninguno (autoservicio)', playbook_version: 'v1', respuesta_cliente: pb.respuesta, pasos: pb.pasos } };

// === 8. REGISTRAR ESTADO + METRICAS ===
const j = $input.item.json;
const sd = $getWorkflowStaticData('global');
sd.casos = sd.casos || [];
sd.metricas = sd.metricas || { total: 0, quejas: 0, incidentes: 0 };
sd.metricas.total += 1;
if (j.resultado === 'INCIDENTE') sd.metricas.incidentes += 1; else sd.metricas.quejas += 1;
sd.casos.push({ caso_id: j.caso_id, tipo: j.resultado, producto: j.producto, categoria: j.categoria, estado: j.estado, canal: j.canal, afectados: j.afectados, equipo: j.equipo_asignado, ia: j.clasificado_por, ts: new Date().toISOString() });
if (sd.casos.length > 500) sd.casos = sd.casos.slice(-500);
j.metricas = sd.metricas;
return { json: j };
